/* Build Gemini request payload. Incoming body expected JSON: { "text": "..." } */
const inputText = $json["body"] && $json["body"].text ? $json["body"].text : ( $json.text || '' );

// safe default
if (!inputText) {
  throw new Error('No text provided in POST body. Send JSON { "text": "..." }');
}

// Create the prompt: ask Gemini to correct grammar and punctuation, keep meaning.
const systemInstruction = "You are an expert English editor. Correct grammar, punctuation, and improve clarity without changing the original meaning. Keep output concise and only return the corrected text.";

const userMessage = `Correct the grammar and punctuation of the following text and return corrected text only:\n\n${inputText}`;

// Build payload aligned to the Gemini REST examples (contents -> parts)
const payload = {
  contents: [
    {
      role: 'user',
      parts: [ { text: userMessage } ]
    }
  ],
  // Lower temperature to make corrections deterministic
  temperature: 0.0
};

return [{ json: { payload } }];

/* Extract corrected text from Gemini response.
   Response structure may vary. We attempt common structure used by the Gemini generateContent responses.
*/

const resp = $json;
let corrected = '';

// Try common paths from Gemini output
try {
  // Some responses return 'candidates' or 'outputs' or 'contents'
  if (resp && resp.candidates && resp.candidates[0] && resp.candidates[0].content) {
    corrected = resp.candidates[0].content;
  } else if (resp && resp.contents && resp.contents[0] && resp.contents[0].parts && resp.contents[0].parts[0] && resp.contents[0].parts[0].text) {
    corrected = resp.contents[0].parts[0].text;
  } else if (resp && resp.output && resp.output[0] && resp.output[0].content) {
    corrected = resp.output[0].content;
  } else if (resp && resp.text) {
    corrected = resp.text;
  } else {
    // fallback: stringify entire response so you can debug
    corrected = JSON.stringify(resp);
  }
} catch (e) {
  corrected = 'Error parsing Gemini response: ' + e.message;
}

return [ { json: { corrected } } ];
